`public class LoggingAdvisor implements StreamAroundAdvisor,CallAroundAdvisor {
	public static final Function<AdvisedRequest, String> DEFAULT_REQUEST_TO_STRING = Record::toString;

	public static final Function<ChatResponse, String> DEFAULT_RESPONSE_TO_STRING = ModelOptionsUtils::toJsonStringPrettyPrinter;

	private static final Logger logger = LoggerFactory.getLogger(SimpleLoggerAdvisor.class);

	private final Function<AdvisedRequest, String> requestToString;

	private final Function<ChatResponse, String> responseToString;

	private final int order;

	public LoggingAdvisor() {
		this(DEFAULT_REQUEST_TO_STRING, DEFAULT_RESPONSE_TO_STRING, 0);
	}

	public LoggingAdvisor(int order) {
		this(DEFAULT_REQUEST_TO_STRING, DEFAULT_RESPONSE_TO_STRING, order);
	}

	public LoggingAdvisor(Function<AdvisedRequest, String> requestToString,
							   Function<ChatResponse, String> responseToString, int order) {
		this.requestToString = requestToString;
		this.responseToString = responseToString;
		this.order = order;
	}

	@Override
	public @NotNull String getName() {
		return this.getClass().getSimpleName();
	}

	@Override
	public int getOrder() {
		return this.order;
	}

	private AdvisedRequest before(AdvisedRequest request) {
		request.messages().forEach(message -> {
			logger.info("request: {}", message);
		});
		return request;
	}

	private void observeAfter(AdvisedResponse advisedResponse) {
//		logger.info("response: {}", this.responseToString.apply());
		logger.info("token使用量,response: {}", advisedResponse.response().getMetadata().getUsage());
	}

	@Override
	public String toString() {
		return SimpleLoggerAdvisor.class.getSimpleName();
	}

	@Override
	public AdvisedResponse aroundCall(AdvisedRequest advisedRequest, CallAroundAdvisorChain chain) {

		advisedRequest = before(advisedRequest);

		AdvisedResponse advisedResponse = chain.nextAroundCall(advisedRequest);

		observeAfter(advisedResponse);

		return advisedResponse;
	}

	@Override
	public Flux<AdvisedResponse> aroundStream(AdvisedRequest advisedRequest, StreamAroundAdvisorChain chain) {

		advisedRequest = before(advisedRequest);

		Flux<AdvisedResponse> advisedResponses = chain.nextAroundStream(advisedRequest);


		return new MessageAggregator().aggregateAdvisedResponse(advisedResponses, this::observeAfter);
	}`

